noncompliant.code:
// Noncompliant: Identical expressions on both sides
if x == x {
    fmt.Println("Always true")
}

// Noncompliant: Same variable used in both operands
result := value + value - value

// Noncompliant: Redundant comparison
isEqual := (name == name)

// Noncompliant: Identical complex expressions
if (user.Age > 18 && user.Active) == (user.Age > 18 && user.Active) {
    // This condition is always true
}

compliant.code:
// Compliant: Different expressions
if x == y {
    fmt.Println("Values are equal")
}

// Compliant: Meaningful arithmetic
result := value * 2

// Compliant: Proper comparison
isEqual := (name == expectedName)

// Compliant: Different conditions
if (user.Age > 18 && user.Active) && (user.Role == "admin") {
    // Meaningful logical combination
}
